  import React, { FC, useEffect, useState } from 'react';
  import { ChessBoard as ChessboardComponent } from 'react-chessboard';
  import { Chess, Move, Piece, Square } from 'chess.js';
  import { useBoardState, useMove } from 'hooks/boardHooks';
  import { Player } from 'types';
  import { useAuth } from 'hooks/authHooks';

  interface Props {
    player: Player;
    onMove: (move: string) => void;
    orientation?: 'white' | 'black';
  }

  const ChessBoard: FC<Props> = ({ player, onMove, orientation = 'white' }) => {
    const { user } = useAuth();
    const { boardState, setBoardState } = useBoardState();
    const { handleMove } = useMove(onMove, player, setBoardState);
    const [board, setBoard] = useState(new Chess());
    const [fen, setFen] = useState<string>(boardState.fen);
    const [activeTarget, setActiveTarget] = useState<{ file: number; rank: number } | null>(null);

    const RANKS = [0, 1, 2, 3, 4, 5, 6, 7];
    const FILES = [0, 1, 2, 3, 4, 5, 6, 7];

    useEffect(() => {
      if (boardState.fen !== fen) {
        setFen(boardState.fen);
        setBoard((prev) => {
          prev.load(boardState.fen);
          return prev;
        });
      }
    }, [boardState.fen]);

    const handleSquareClick = (square: Square) => {
      if (!user) return;
      if (board.turn() !== player) return;
      if (activeTarget === null) {
        // First click: select piece.
        const file = square.charCodeAt(0) - 'a'.charCodeAt(0);
        const rank = parseInt(square[1]) - 1;
        setActiveTarget({ file, rank });
      } else {
        // Second click: attempt move.
        const file = square.charCodeAt(0) - 'a'.charCodeAt(0);
        const rank = parseInt(square[1]) - 1;
        const from = `${String.fromCharCode(
          'a'.charCodeAt(0) + activeTarget.file
        )}${activeTarget.rank + 1}`;
        const to = `${String.fromCharCode('a'.charCodeAt(0) + file)}${rank + 1}`;
        const move = board.move({ from, to });
        if (move) {
          handleMove(move);
          setActiveTarget(null);
        } else {
          setActiveTarget(null);
        }
      }
    };

    const getPiece = (square: Square) => {
      const piece = board.get(square);
      return piece;
    };

    const getPieceStyle = (piece: Piece | null) => {
      if (!piece) return '';
      const style = piece.color === 'w' ? 'white' : 'black';
      switch (piece.type) {
        case 'p':
          return `pawn-${style}`;
        case 'r':
          return `rook-${style}`;
        case 'n':
          return `knight-${style}`;
        case 'b':
          return `bishop-${style}`;
        case 'q':
          return `queen-${style}`;
        case 'k':
          return `king-${style}`;
        default:
          return '';
      }
    };

    return (
      <div style={{ position: 'relative' }}>
        <ChessboardComponent
          arePiecesDraggable={true}
          areArrowsAllowed={false}
          areCornersVisible={false}
          boardOrientation={orientation}
          customBoardStyle={{ width: '400px', height: '400px' }}
