                  <button
                    key={d}
                    onClick={() => setDifficulty(d)}
                    className={`py-2.5 rounded-xl font-bold text-xs uppercase transition-all duration-200 ${
                      difficulty === d 
                        ? 'bg-brown text-gold shadow-lg shadow-brown/20' 
                        : 'text-brown/40 hover:text-brown/60'
