      {gameState === GameState.MENU && (
        <div className="absolute inset-0 bg-cream/90 backdrop-blur-xl z-50 flex flex-col items-center justify-center p-6 text-center animate-in fade-in zoom-in-95 duration-500">
          <div className="bg-white p-8 md:p-10 rounded-[2rem] shadow-[0_24px_48px_-12px_rgba(85,30,25,0.12)] border border-white max-w-md w-full transform transition-all duration-500 hover:scale-[1.01]">
